    include: [
      {
        model: Department,
        as: 'divisions',
        include: [
          {
            model: Employee,
            as: 'staff',
            include: [
              {
                model: Project,
                as: 'assignments',
              },
            ],
          },
        ],
      },
    ],
  });

  const outputPath = path.join(__dirname, 'output.json');
  fs.writeFileSync(outputPath, JSON.stringify(company, null, 2));

  await sequelize.close();
};

run().catch((error) => {
  console.error(error);
  process.exitCode = 1;
});
